// HasOperation applies the HasEdge predicate on the "operation" edge.
func HasOperation() predicate.InventoryOperationItem {
	return predicate.InventoryOperationItem(func(s *sql.Selector) {
		step := sqlgraph.NewStep(
			sqlgraph.From(Table, FieldID),
			sqlgraph.Edge(sqlgraph.M2O, true, OperationTable, OperationColumn),
		)
		sqlgraph.HasNeighbors(s, step)
	})
}

// HasOperationWith applies the HasEdge predicate on the "operation" edge with a given conditions (other predicates).
func HasOperationWith(preds ...predicate.InventoryOperation) predicate.InventoryOperationItem {
	return predicate.InventoryOperationItem(func(s *sql.Selector) {
		step := newOperationStep()
		sqlgraph.HasNeighborsWith(s, step, func(s *sql.Selector) {
			for _, p := range preds {
				p(s)
			}
		})
	})
}

// And groups predicates with the AND operator between them.
func And(predicates ...predicate.InventoryOperationItem) predicate.InventoryOperationItem {
	return predicate.InventoryOperationItem(sql.AndPredicates(predicates...))
}

// Or groups predicates with the OR operator between them.
func Or(predicates ...predicate.InventoryOperationItem) predicate.InventoryOperationItem {
	return predicate.InventoryOperationItem(sql.OrPredicates(predicates...))
}

// Not applies the not operator on the given predicate.
func Not(p predicate.InventoryOperationItem) predicate.InventoryOperationItem {
	return predicate.InventoryOperationItem(sql.NotPredicates(p))
}
